import React, { useState, useRef } from 'react';
import Webcam from 'react-webcam';
import axios from 'axios';
import '../ImageProject.css'; 

const ImageProject = () => {
  const [class1Mode, setClass1Mode] = useState(null);
  const [class2Mode, setClass2Mode] = useState(null);
  const webcamRef1 = useRef(null);
  const webcamRef2 = useRef(null);
  const [capturedImages1, setCapturedImages1] = useState([]);
  const [capturedImages2, setCapturedImages2] = useState([]);

  const handleCapture = (webcamRef, setCapturedImages) => {
    if (webcamRef.current) {
      const imageSrc = webcamRef.current.getScreenshot();
      setCapturedImages(prevImages => [...prevImages, imageSrc]);
    }
  };

  const handleSendBatch = async () => {
    const formData = new FormData();

    capturedImages1.forEach((image, index) => {
      const byteString = atob(image.split(',')[1]);
      const mimeString = image.split(',')[0].split(':')[1].split(';')[0];
      const ab = new ArrayBuffer(byteString.length);
      const ia = new Uint8Array(ab);
      for (let i = 0; i < byteString.length; i++) {
        ia[i] = byteString.charCodeAt(i);
      }
      const blob = new Blob([ab], { type: mimeString });
      formData.append(`class1_image_${index}`, blob, `class1_image${index}.jpeg`);
    });

    capturedImages2.forEach((image, index) => {
      const byteString = atob(image.split(',')[1]);
      const mimeString = image.split(',')[0].split(':')[1].split(';')[0];
      const ab = new ArrayBuffer(byteString.length);
      const ia = new Uint8Array(ab);
      for (let i = 0; i < byteString.length; i++) {
        ia[i] = byteString.charCodeAt(i);
      }
      const blob = new Blob([ab], { type: mimeString });
      formData.append(`class2_image_${index}`, blob, `class2_image${index}.jpeg`);
    });

    try {
      const response = await axios.post('http://127.0.0.1:8000/upload_batch/', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      console.log('Batch sent successfully:', response.data);
    } catch (error) {
      console.error('Error sending batch:', error);
    }
  };

  return (
    <div className="container">
      <div className="left-panel">
        <div className="class-section">
          <h2>Class 1</h2>
          <button onClick={() => setClass1Mode('upload')}>Upload Image</button>
          <button onClick={() => setClass1Mode('capture')}>Capture Image</button>
          {class1Mode === 'capture' && (
            <div className="webcam-container">
              <Webcam
                audio={false}
                ref={webcamRef1}
                screenshotFormat="image/jpeg"
                width={320}
                height={240}
              />
              <button onClick={() => handleCapture(webcamRef1, setCapturedImages1)}>Capture</button>
              <div className="captured-images">
                {capturedImages1.length > 0 && <h3>Captured Images (Class 1):</h3>}
                {capturedImages1.map((image, index) => (
                  <div key={index} className="image-wrapper">
                    <img src={image} alt={`Class 1 Capture ${index + 1}`} />
                    <button className="delete-btn" onClick={() => setCapturedImages1(prevImages => prevImages.filter((_, i) => i !== index))}>
                      ❌
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="class-section">
          <h2>Class 2</h2>
          <button onClick={() => setClass2Mode('upload')}>Upload Image</button>
          <button onClick={() => setClass2Mode('capture')}>Capture Image</button>
          {class2Mode === 'capture' && (
            <div className="webcam-container">
              <Webcam
                audio={false}
                ref={webcamRef2}
                screenshotFormat="image/jpeg"
                width={320}
                height={240}
              />
              <button onClick={() => handleCapture(webcamRef2, setCapturedImages2)}>Capture</button>
              <div className="captured-images">
                {capturedImages2.length > 0 && <h3>Captured Images (Class 2):</h3>}
                {capturedImages2.map((image, index) => (
                  <div key={index} className="image-wrapper">
                    <img src={image} alt={`Class 2 Capture ${index + 1}`} />
                    <button className="delete-btn" onClick={() => setCapturedImages2(prevImages => prevImages.filter((_, i) => i !== index))}>
                      ❌
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="center-panel">
        <div className="box">
          <h2>Train Model</h2>
          <button onClick={handleSendBatch}>Send Images for Both Classes</button>
        </div>
      </div>
    </div>
  );
};

export default ImageProject;
